import React, { useState, useEffect } from 'react';
import api from '../services/api';

function Relatorios() {
    const [filtros, setFiltros] = useState({ cliente_id: '', data_inicio: '', data_fim: '', categoria_id: '' });
    const [mostrarTempo, setMostrarTempo] = useState(false);
    const [resultados, setResultados] = useState([]);
    const [clientes, setClientes] = useState([]);
    const [categorias, setCategorias] = useState([]);

    useEffect(() => {
        const loadData = async () => {
            const clientesRes = await api.get('/clientes');
            setClientes(clientesRes.data);
            const catRes = await api.get('/clientes/categorias');
            setCategorias(catRes.data);
        };
        loadData();
    }, []);

    const gerarRelatorio = async () => {
        const params = { ...filtros, mostrar_tempo: mostrarTempo };
        const res = await api.get('/relatorios', { params });
        setResultados(res.data.dados);
    };

    return (
        <div>
            <h2>Relatórios</h2>
            <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '20px' }}>
                <select value={filtros.cliente_id} onChange={e => setFiltros({...filtros, cliente_id: e.target.value})}>
                    <option value="">Todos os clientes</option>
                    {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                </select>
                <input type="date" value={filtros.data_inicio} onChange={e => setFiltros({...filtros, data_inicio: e.target.value})} placeholder="Data início" />
                <input type="date" value={filtros.data_fim} onChange={e => setFiltros({...filtros, data_fim: e.target.value})} placeholder="Data fim" />
                <select value={filtros.categoria_id} onChange={e => setFiltros({...filtros, categoria_id: e.target.value})}>
                    <option value="">Todos os serviços</option>
                    {categorias.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                </select>
                <label>
                    <input type="checkbox" checked={mostrarTempo} onChange={e => setMostrarTempo(e.target.checked)} />
                    Mostrar tempo gasto
                </label>
                <button onClick={gerarRelatorio}>Gerar Relatório</button>
            </div>
            <table border="1" cellPadding="8" style={{ borderCollapse: 'collapse', width: '100%' }}>
                <thead>
                    <tr>
                        <th>Cliente</th><th>Data</th><th>Equipamento</th><th>Serviço</th>
                        <th>Tipo</th><th>Valor</th>
                        {mostrarTempo && <th>Tempo real</th>}
                    </tr>
                </thead>
                <tbody>
                    {resultados.map(os => (
                        <tr key={os.id}>
                            <td>{os.cliente_nome}</td>
                            <td>{os.data_conclusao}</td>
                            <td>{os.equipamento} {os.modelo}</td>
                            <td>{os.servico_realizado}</td>
                            <td>{os.tipo_atendimento}</td>
                            <td>R$ {parseFloat(os.preco_final).toFixed(2)}</td>
                            {mostrarTempo && <td>{Math.floor(os.tempo_acumulado_segundos / 60)} min</td>}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default Relatorios;
